// ============================================================
// FEDKO DEMO DATA — COURSES (CCMAS-Aligned)
// 8 courses/semester × 2 semesters × 4 years = 64 per dept
// CU legend: 1CU=1x/wk | 2CU=2x/wk | 3CU=2x/wk+1 | 4CU=2x/wk
// ============================================================

export interface Course {
  code: string;
  title: string;
  creditUnit: number;
  level: 100 | 200 | 300 | 400;
  semester: 1 | 2;
  dept: string;        // dept code or "GNS"/"GST" for general studies
  isGeneral?: boolean; // GST/GNS courses taken by multiple depts
  type: "core" | "elective" | "general" | "practical";
  hoursPerWeek: number; // 1CU→1, 2CU→2, 3CU→3, 4CU→2(+extra practical)
}

