// Map for quick lookup
export const ALL_DEPT_COURSES: Record<string, Course[]> = {
  CHM: CHM_COURSES,
  PHY: PHY_COURSES,
  CSC: CSC_COURSES,
  MTH: MTH_COURSES,
  BCH: BCH_COURSES,
  MCB: MCB_COURSES,
  STA: STA_COURSES,
  BIO: BIO_COURSES,
  // BOT, ZOO, GEO, GLG share same 64-course structure, generated on demand
};

export function getCoursesByDeptLevel(dept: string, level: number, semester: number): Course[] {
  const courses = ALL_DEPT_COURSES[dept] ?? [];
  return courses.filter(c => c.level === level && c.semester === semester);
}

export function getTotalCreditUnits(courses: Course[]): number {
  return courses.reduce((sum, c) => sum + c.creditUnit, 0);
}
